const allowed = ['platform', 'resource', 'record_count_visible', 'status_counts', 'visible_field_names', 'category_counts', 'status_code', 'content_type'];
return items.map((item) => {
  let parsed = {};
  const raw = item.json.stdout || item.json.data || item.json;
  if (typeof raw === 'string') {
    try { parsed = JSON.parse(raw); } catch (error) { parsed = { parse_error: String(error) }; }
  } else {
    parsed = raw;
  }
  const out = {};
  for (const key of allowed) {
    if (parsed[key] !== undefined) out[key] = parsed[key];
  }
  out.summary_time_utc = new Date().toISOString();
  out.raw_records_emitted = false;
  out.certopus_writes_attempted = false;
  out.certificate_operations_attempted = false;
  return { json: out };
});

const lines = ['# Certopus read-only health summary', '', `Generated: ${new Date().toISOString()}`, '', 'Safety: Certopus GET-only via X-API-KEY; raw records omitted; no certificate operations/sends/mutations attempted.', ''];
for (const item of items) {
  const j = item.json;
  const status = j.status_code ? `HTTP ${j.status_code}` : 'status unknown';
  const count = j.record_count_visible ?? 'N/A';
  const buckets = j.status_counts && Object.keys(j.status_counts).length ? `; status buckets: ${JSON.stringify(j.status_counts)}` : '';
  const categories = j.category_counts && Object.keys(j.category_counts).length ? '; category counts present' : '';
  lines.push(`- ${j.resource || 'unknown'}: ${status}; visible count ${count}${buckets}${categories}`);
}
lines.push('', 'No raw Certopus records, recipient data, certificate payloads, organisation names/branding assets, SMTP settings, wallet details, or API key material emitted.');
return [{ json: { digest_markdown: lines.join('\n'), raw_records_emitted: false, certopus_writes_attempted: false, certificate_operations_attempted: false } }];
